import React, { useState } from 'react';
import styled, { keyframes } from 'styled-components';
import { Sparkles, Bot, Zap, Code, Database, Cloud, Rocket } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const fadeInUp = keyframes`
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
`;

const float = keyframes`
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
`;

const Container = styled.div`
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  overflow-x: hidden;
`;

const Hero = styled.section`
  padding: 60px 20px;
  text-align: center;
  color: white;
  animation: ${fadeInUp} 0.8s ease-out;
`;

const HeroContent = styled.div`
  max-width: 800px;
  margin: 0 auto;
`;

const Title = styled.h1`
  font-size: 3.5rem;
  font-weight: 800;
  margin-bottom: 20px;
  background: linear-gradient(45deg, #fff, #e2e8f0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  
  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const Subtitle = styled.p`
  font-size: 1.25rem;
  margin-bottom: 30px;
  opacity: 0.9;
  line-height: 1.6;
`;

const CTAButton = styled.button`
  background: white;
  color: #667eea;
  border: none;
  padding: 16px 32px;
  border-radius: 50px;
  font-size: 18px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
  
  &:hover {
    transform: translateY(-3px);
    box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
  }
`;

const Features = styled.section`
  padding: 80px 20px;
  background: white;
`;

const FeaturesContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  text-align: center;
  font-size: 2.5rem;
  color: #1a202c;
  margin-bottom: 60px;
  font-weight: 700;
`;

const FeatureGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 40px;
  margin-bottom: 60px;
`;

const FeatureCard = styled.div`
  background: #f8fafc;
  border-radius: 20px;
  padding: 30px;
  text-align: center;
  transition: all 0.3s ease;
  border: 2px solid transparent;
  animation: ${fadeInUp} 0.6s ease-out ${props => props.delay || '0s'};
  
  &:hover {
    transform: translateY(-5px);
    border-color: #667eea;
    box-shadow: 0 15px 40px rgba(102, 126, 234, 0.1);
  }
`;

const FeatureIcon = styled.div`
  width: 80px;
  height: 80px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  border-radius: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 20px;
  color: white;
  animation: ${float} 3s ease-in-out infinite;
  animation-delay: ${props => props.delay || '0s'};
`;

const FeatureTitle = styled.h3`
  font-size: 1.5rem;
  color: #1a202c;
  margin-bottom: 15px;
  font-weight: 600;
`;

const FeatureDescription = styled.p`
  color: #64748b;
  line-height: 1.6;
`;

const TechStack = styled.section`
  padding: 80px 20px;
  background: #1a202c;
  color: white;
`;

const TechGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 30px;
  max-width: 800px;
  margin: 0 auto;
`;

const TechItem = styled.div`
  text-align: center;
  padding: 20px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 15px;
  transition: all 0.3s ease;
  
  &:hover {
    background: rgba(255, 255, 255, 0.1);
    transform: translateY(-5px);
  }
`;

const Templates = styled.section`
  padding: 80px 20px;
  background: #f8fafc;
`;

const TemplateGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  max-width: 1000px;
  margin: 0 auto;
`;

const TemplateCard = styled.div`
  background: white;
  border-radius: 15px;
  padding: 25px;
  box-shadow: 0 5px 20px rgba(0, 0, 0, 0.1);
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 15px 40px rgba(0, 0, 0, 0.15);
  }
`;

function Home() {
  const navigate = useNavigate();
  const [selectedTemplate, setSelectedTemplate] = useState(null);

  const features = [
    {
      icon: <Bot size={40} />,
      title: "AI-Powered Builder",
      description: "Tell our AI what you want to build and watch it generate complete applications instantly."
    },
    {
      icon: <Code size={40} />,
      title: "Full-Stack Generation",
      description: "Complete React frontend, FastAPI backend, and MySQL database - all generated automatically."
    },
    {
      icon: <Zap size={40} />,
      title: "Unlimited Projects",
      description: "Build as many applications as you want. No limits, no restrictions, no pricing tiers."
    },
    {
      icon: <Database size={40} />,
      title: "Smart Integrations",
      description: "Automatic integration with Stripe, OpenAI, Google APIs, and more external services."
    },
    {
      icon: <Cloud size={40} />,
      title: "One-Click Deploy",
      description: "Deploy to Docker, Vercel, AWS, or any cloud platform with automatically generated configs."
    },
    {
      icon: <Rocket size={40} />,
      title: "Production Ready",
      description: "Generated code follows best practices with proper authentication, error handling, and security."
    }
  ];

  const techStack = [
    { name: "React", desc: "Frontend Framework" },
    { name: "FastAPI", desc: "Python Backend" },
    { name: "MySQL", desc: "Database" },
    { name: "Docker", desc: "Containerization" }
  ];

  const templates = [
    { 
      name: "Dashboard", 
      desc: "Analytics dashboard with charts and widgets",
      features: ["Charts", "Widgets", "Real-time data"]
    },
    { 
      name: "E-commerce", 
      desc: "Complete online store with payments",
      features: ["Products", "Cart", "Stripe integration"]
    },
    { 
      name: "Blog/CMS", 
      desc: "Content management system",
      features: ["Posts", "Comments", "Admin panel"]
    },
    { 
      name: "Chat App", 
      desc: "Real-time messaging platform",
      features: ["Real-time chat", "File sharing", "Rooms"]
    },
    { 
      name: "CRM", 
      desc: "Customer relationship management",
      features: ["Contacts", "Deals", "Analytics"]
    },
    { 
      name: "API Service", 
      desc: "RESTful API with documentation",
      features: ["REST API", "Swagger docs", "Authentication"]
    }
  ];

  return (
    <Container>
      <Hero>
        <HeroContent>
          <Title>
            AI App Builder Agent
            <Sparkles size={40} style={{ marginLeft: '10px', verticalAlign: 'middle' }} />
          </Title>
          <Subtitle>
            Tell me what you want to build, and I'll generate a complete full-stack application
            with React frontend, FastAPI backend, MySQL database, and deployment configs.
            <br />
            <strong>Unlimited projects. No restrictions.</strong>
          </Subtitle>
          <CTAButton onClick={() => navigate('/builder')}>
            Start Building Now →
          </CTAButton>
        </HeroContent>
      </Hero>

      <Features>
        <FeaturesContainer>
          <SectionTitle>🚀 Unlimited Full-Stack Development</SectionTitle>
          <FeatureGrid>
            {features.map((feature, index) => (
              <FeatureCard key={index} delay={`${index * 0.1}s`}>
                <FeatureIcon delay={`${index * 0.2}s`}>
                  {feature.icon}
                </FeatureIcon>
                <FeatureTitle>{feature.title}</FeatureTitle>
                <FeatureDescription>{feature.description}</FeatureDescription>
              </FeatureCard>
            ))}
          </FeatureGrid>
        </FeaturesContainer>
      </Features>

      <TechStack>
        <FeaturesContainer>
          <SectionTitle style={{ color: 'white' }}>🛠️ Modern Tech Stack</SectionTitle>
          <TechGrid>
            {techStack.map((tech, index) => (
              <TechItem key={index}>
                <h3 style={{ marginBottom: '10px', fontSize: '1.2rem' }}>{tech.name}</h3>
                <p style={{ opacity: 0.8 }}>{tech.desc}</p>
              </TechItem>
            ))}
          </TechGrid>
        </FeaturesContainer>
      </TechStack>

      <Templates>
        <FeaturesContainer>
          <SectionTitle>📋 Ready-to-Use Templates</SectionTitle>
          <TemplateGrid>
            {templates.map((template, index) => (
              <TemplateCard key={index}>
                <h3 style={{ marginBottom: '10px', color: '#1a202c' }}>{template.name}</h3>
                <p style={{ color: '#64748b', marginBottom: '15px' }}>{template.desc}</p>
                <div>
                  {template.features.map((feature, i) => (
                    <span 
                      key={i}
                      style={{
                        background: '#667eea',
                        color: 'white',
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        margin: '2px',
                        display: 'inline-block'
                      }}
                    >
                      {feature}
                    </span>
                  ))}
                </div>
              </TemplateCard>
            ))}
          </TemplateGrid>
        </FeaturesContainer>
      </Templates>
    </Container>
  );
}

export default Home;
